import React from 'react';

const ReviewsAndRatings = () => {
  // Dummy data for reviews and ratings
  const reviews = [
    { id: 1, rating: 5, text: 'Great service, fixed my appliances quickly!' },
    { id: 2, rating: 4, text: 'Excellent price transperancy, highly recommend!' },
    { id: 3, rating: 5, text: 'Adding Parts to the cart and tracking status is so cool !!' },
    { id: 4, rating: 5, text: 'Great service, fixed my appliances quickly!' },
    { id: 5, rating: 4, text: 'Excellent price transperancy, highly recommend!' },
    { id: 6, rating: 5, text: 'Adding Parts to the cart and tracking status is so cool !!' },
    // Add more reviews as needed
  ];

  return (
    <div className="reviews-and-ratings">
      <h2>Reviews and Ratings</h2>
      <div className="review-cards">
        {reviews.map(review => (
          <div key={review.id} className="review-card">
            <div className="customer-info">
              <span className="customer-name">{review.customer}</span>
              <span className="rating-stars">{'★'.repeat(review.rating)}</span>
            </div>
            <div className="review-text">{review.text}</div>
          </div>
        ))}
      </div>
    </div>
  );
};


export default ReviewsAndRatings;
